 1	import React, { ChangeEvent, Dispatch, FC, SetStateAction } from 'react';
 2	
 3	import { V1CPU } from '@kubevirt-ui/kubevirt-api/kubevirt';
 4	import { getCPUComponentTitle } from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/components/CPUTopologyInput/utils/utils';
 5	import {
 6	  CPUComponent,
 7	  getUpdatedCPU,
 8	} from '@kubevirt-utils/components/CPUMemoryModal/components/CPUInput/utils/utils';
 9	import { GridItem, NumberInput, Text } from '@patternfly/react-core';
10	
11	type CPUComponentInputProps = {
12	  cpu: V1CPU;
13	  cpuComponent: CPUComponent;
14	  isDisabled: boolean;
15	  setCPU: Dispatch<SetStateAction<V1CPU>>;
16	};
17	
18	const CPUComponentInput: FC<CPUComponentInputProps> = ({
19	  cpu,
20	  cpuComponent,
21	  isDisabled,
22	  setCPU,
23	}) => {
24	  return (
25	    <>
26	      <GridItem span={3}>
27	        <Text disabled={isDisabled}>{getCPUComponentTitle(cpuComponent)}</Text>
28	      </GridItem>
29	      <GridItem span={9}>
30	        <NumberInput
31	          onChange={(e: ChangeEvent<HTMLInputElement>) => {
32	            const newNumber = +e?.target?.value;
33	            setCPU(getUpdatedCPU(cpu, newNumber, cpuComponent));
34	          }}
35	          inputName="cpu-sockets-input"
36	          isDisabled={isDisabled}
37	          min={1}
38	          onMinus={() => setCPU(getUpdatedCPU(cpu, +cpu?.[cpuComponent] - 1, cpuComponent))}
39	          onPlus={() => setCPU(getUpdatedCPU(cpu, +cpu?.[cpuComponent] + 1, cpuComponent))}
40	          value={cpu?.[cpuComponent]}
41	        />
42	      </GridItem>
43	    </>
44	  );
45	};
46	
47	export default CPUComponentInput;

